```hcl
resource "azuread_conditional_access_policy" "<example_resource_name>" {
  display_name = "<example_resource_name>"
  state        = "enabled" # Critical: must be enabled (not report-only) to enforce

  conditions {
    users {
      included_roles = ["<example_role_id>"] # Critical: target admin directory roles (e.g., Global Administrator)
    }
    applications {
      included_applications = ["All"] # Critical: apply to all cloud apps
    }
  }

  session_controls {
    sign_in_frequency          = 4          # Critical: enforce reauth at or below 4 hours
    sign_in_frequency_interval = "hours"   # Critical: time-based frequency in hours
    persistent_browser_mode    = "never"   # Critical: enforce non-persistent browser sessions
  }
}
```

```hcl
resource "azuread_conditional_access_policy" "<example_resource_name>" {
  display_name = "<example_resource_name>"
  state        = "enabled" # Critical: enforce policy

  conditions {
    users {
      include_users = ["All"] # Critical: apply to all users
    }
    applications {
      include_applications = ["All"] # Critical: apply to all apps
    }
    sign_in_risk_levels = ["medium", "high"] # Critical: protect Medium and High sign-in risks
    client_app_types    = ["all"]
  }

  grant_controls {
    operator          = "OR"
    built_in_controls = ["mfa"] # Critical: require MFA
  }

  session_controls {
    sign_in_frequency_interval = "everyTime" # Critical: require reauth every time
  }
}
```

